    83→        heartbeatTimer.reset(rebalanceConfig.heartbeatIntervalMs);
    84→
    85→        if (log.isTraceEnabled()) {
    86→            log.trace("Sending heartbeat request with {}ms remaining on timer", heartbeatTimer.remainingMs());
    87→        }
    88→    }
