   250→    /**
   251→     * Postprocess the configuration so that exponential backoff is disabled when reconnect backoff
   252→     * is explicitly configured but the maximum reconnect backoff is not explicitly configured.
   253→     *
   254→     * @param config                    The config object.
   255→     * @param parsedValues              The parsedValues as provided to postProcessParsedConfig.
   256→     *
   257→     * @return                          The new values which have been set as described in postProcessParsedConfig.
   258→     */
   259→    public static Map<String, Object> postProcessReconnectBackoffConfigs(AbstractConfig config,
   260→                                                                         Map<String, Object> parsedValues) {
   261→        HashMap<String, Object> rval = new HashMap<>();
   262→        Map<String, Object> originalConfig = config.originals();
   263→        if ((!originalConfig.containsKey(RECONNECT_BACKOFF_MAX_MS_CONFIG)) &&
   264→            originalConfig.containsKey(RECONNECT_BACKOFF_MS_CONFIG)) {
   265→            log.warn("Disabling exponential reconnect backoff because {} is set, but {} is not.",
   266→                    RECONNECT_BACKOFF_MS_CONFIG, RECONNECT_BACKOFF_MAX_MS_CONFIG);
   267→            rval.put(RECONNECT_BACKOFF_MAX_MS_CONFIG, parsedValues.get(RECONNECT_BACKOFF_MS_CONFIG));
   268→        }
   269→        return rval;
   270→    }
   271→
   272→    /**
   273→     * Log warning if the exponential backoff is disabled due to initial backoff value is greater than max backoff value.
   274→     *
   275→     * @param config                    The config object.
   276→     */
   277→    public static void warnDisablingExponentialBackoff(AbstractConfig config) {
   278→        long retryBackoffMs = config.getLong(RETRY_BACKOFF_MS_CONFIG);
   279→        long retryBackoffMaxMs = config.getLong(RETRY_BACKOFF_MAX_MS_CONFIG);
   280→        if (retryBackoffMs > retryBackoffMaxMs) {
   281→            log.warn("Configuration '{}' with value '{}' is greater than configuration '{}' with value '{}'. " +
   282→                    "A static backoff with value '{}' will be applied.",
   283→                RETRY_BACKOFF_MS_CONFIG, retryBackoffMs,
   284→                RETRY_BACKOFF_MAX_MS_CONFIG, retryBackoffMaxMs, retryBackoffMaxMs);
   285→        }
   286→
   287→        long connectionSetupTimeoutMs = config.getLong(SOCKET_CONNECTION_SETUP_TIMEOUT_MS_CONFIG);
   288→        long connectionSetupTimeoutMaxMs = config.getLong(SOCKET_CONNECTION_SETUP_TIMEOUT_MAX_MS_CONFIG);
   289→        if (connectionSetupTimeoutMs > connectionSetupTimeoutMaxMs) {
   290→            log.warn("Configuration '{}' with value '{}' is greater than configuration '{}' with value '{}'. " +
   291→                    "A static connection setup timeout with value '{}' will be applied.",
   292→                SOCKET_CONNECTION_SETUP_TIMEOUT_MS_CONFIG, connectionSetupTimeoutMs,
   293→                SOCKET_CONNECTION_SETUP_TIMEOUT_MAX_MS_CONFIG, connectionSetupTimeoutMaxMs, connectionSetupTimeoutMaxMs);
   294→        }
   295→    }
