   297→    public static void postValidateSaslMechanismConfig(AbstractConfig config) {
   298→        SecurityProtocol securityProtocol = SecurityProtocol.forName(config.getString(CommonClientConfigs.SECURITY_PROTOCOL_CONFIG));
   299→        String clientSaslMechanism = config.getString(SaslConfigs.SASL_MECHANISM);
   300→        if (securityProtocol == SecurityProtocol.SASL_PLAINTEXT || securityProtocol == SecurityProtocol.SASL_SSL) {
   301→            if (clientSaslMechanism == null || clientSaslMechanism.isEmpty()) {
   302→                throw new ConfigException(SaslConfigs.SASL_MECHANISM, null, "When the " + CommonClientConfigs.SECURITY_PROTOCOL_CONFIG +
   303→                        " configuration enables SASL, mechanism must be non-null and non-empty string.");
   304→            }
   305→        }
   306→    }
