   240→            "for the client. Rebootstrap is also triggered if connection cannot be established to any of the brokers for " +
   241→            "<code>metadata.recovery.rebootstrap.trigger.ms</code> milliseconds or if server requests rebootstrap.";
   242→    public static final String DEFAULT_METADATA_RECOVERY_STRATEGY = MetadataRecoveryStrategy.REBOOTSTRAP.name;
   243→
   244→    public static final String METADATA_RECOVERY_REBOOTSTRAP_TRIGGER_MS_CONFIG = "metadata.recovery.rebootstrap.trigger.ms";
   245→    public static final String METADATA_RECOVERY_REBOOTSTRAP_TRIGGER_MS_DOC = "If a client configured to rebootstrap using " +
   246→            "<code>metadata.recovery.strategy=rebootstrap</code> is unable to obtain metadata from any of the brokers in the last known " +
   247→            "metadata for this interval, client repeats the bootstrap process using <code>bootstrap.servers</code> configuration.";
   248→    public static final long DEFAULT_METADATA_RECOVERY_REBOOTSTRAP_TRIGGER_MS = 300 * 1000;
   249→
   250→    /**
   251→     * Postprocess the configuration so that exponential backoff is disabled when reconnect backoff
   252→     * is explicitly configured but the maximum reconnect backoff is not explicitly configured.
   253→     *
   254→     * @param config                    The config object.
   255→     * @param parsedValues              The parsedValues as provided to postProcessParsedConfig.
   256→     *
   257→     * @return                          The new values which have been set as described in postProcessParsedConfig.
   258→     */
   259→    public static Map<String, Object> postProcessReconnectBackoffConfigs(AbstractConfig config,
   260→                                                                         Map<String, Object> parsedValues) {
   261→        HashMap<String, Object> rval = new HashMap<>();
   262→        Map<String, Object> originalConfig = config.originals();
   263→        if ((!originalConfig.containsKey(RECONNECT_BACKOFF_MAX_MS_CONFIG)) &&
   264→            originalConfig.containsKey(RECONNECT_BACKOFF_MS_CONFIG)) {
   265→            log.warn("Disabling exponential reconnect backoff because {} is set, but {} is not.",
   266→                    RECONNECT_BACKOFF_MS_CONFIG, RECONNECT_BACKOFF_MAX_MS_CONFIG);
   267→            rval.put(RECONNECT_BACKOFF_MAX_MS_CONFIG, parsedValues.get(RECONNECT_BACKOFF_MS_CONFIG));
   268→        }
   269→        return rval;
   270→    }
   271→
   272→    /**
   273→     * Log warning if the exponential backoff is disabled due to initial backoff value is greater than max backoff value.
   274→     *
   275→     * @param config                    The config object.
   276→     */
   277→    public static void warnDisablingExponentialBackoff(AbstractConfig config) {
   278→        long retryBackoffMs = config.getLong(RETRY_BACKOFF_MS_CONFIG);
   279→        long retryBackoffMaxMs = config.getLong(RETRY_BACKOFF_MAX_MS_CONFIG);
   280→        if (retryBackoffMs > retryBackoffMaxMs) {
   281→            log.warn("Configuration '{}' with value '{}' is greater than configuration '{}' with value '{}'. " +
   282→                    "A static backoff with value '{}' will be applied.",
   283→                RETRY_BACKOFF_MS_CONFIG, retryBackoffMs,
   284→                RETRY_BACKOFF_MAX_MS_CONFIG, retryBackoffMaxMs, retryBackoffMaxMs);
   285→        }
   286→
   287→        long connectionSetupTimeoutMs = config.getLong(SOCKET_CONNECTION_SETUP_TIMEOUT_MS_CONFIG);
   288→        long connectionSetupTimeoutMaxMs = config.getLong(SOCKET_CONNECTION_SETUP_TIMEOUT_MAX_MS_CONFIG);
   289→        if (connectionSetupTimeoutMs > connectionSetupTimeoutMaxMs) {
   290→            log.warn("Configuration '{}' with value '{}' is greater than configuration '{}' with value '{}'. " +
   291→                    "A static connection setup timeout with value '{}' will be applied.",
   292→                SOCKET_CONNECTION_SETUP_TIMEOUT_MS_CONFIG, connectionSetupTimeoutMs,
   293→                SOCKET_CONNECTION_SETUP_TIMEOUT_MAX_MS_CONFIG, connectionSetupTimeoutMaxMs, connectionSetupTimeoutMaxMs);
   294→        }
   295→    }
   296→
   297→    public static void postValidateSaslMechanismConfig(AbstractConfig config) {
   298→        SecurityProtocol securityProtocol = SecurityProtocol.forName(config.getString(CommonClientConfigs.SECURITY_PROTOCOL_CONFIG));
   299→        String clientSaslMechanism = config.getString(SaslConfigs.SASL_MECHANISM);
   300→        if (securityProtocol == SecurityProtocol.SASL_PLAINTEXT || securityProtocol == SecurityProtocol.SASL_SSL) {
   301→            if (clientSaslMechanism == null || clientSaslMechanism.isEmpty()) {
   302→                throw new ConfigException(SaslConfigs.SASL_MECHANISM, null, "When the " + CommonClientConfigs.SECURITY_PROTOCOL_CONFIG +
   303→                        " configuration enables SASL, mechanism must be non-null and non-empty string.");
   304→            }
   305→        }
   306→    }
   307→
   308→    public static List<MetricsReporter> metricsReporters(AbstractConfig config) {
   309→        return metricsReporters(Collections.emptyMap(), config);
   310→    }
   311→
   312→    public static List<MetricsReporter> metricsReporters(String clientId, AbstractConfig config) {
   313→        return metricsReporters(Collections.singletonMap(CommonClientConfigs.CLIENT_ID_CONFIG, clientId), config);
   314→    }
   315→
   316→    public static List<MetricsReporter> metricsReporters(Map<String, Object> clientIdOverride, AbstractConfig config) {
   317→        return config.getConfiguredInstances(CommonClientConfigs.METRIC_REPORTER_CLASSES_CONFIG,
   318→                MetricsReporter.class, clientIdOverride);
   319→    }
   320→
   321→    public static Optional<ClientTelemetryReporter> telemetryReporter(String clientId, AbstractConfig config) {
   322→        if (!config.getBoolean(CommonClientConfigs.ENABLE_METRICS_PUSH_CONFIG)) {
   323→            return Optional.empty();
   324→        }
   325→
   326→        ClientTelemetryReporter telemetryReporter = new ClientTelemetryReporter(Time.SYSTEM);
   327→        telemetryReporter.configure(config.originals(Collections.singletonMap(CommonClientConfigs.CLIENT_ID_CONFIG, clientId)));
   328→        return Optional.of(telemetryReporter);
   329→    }
   330→}
